'use client';

import { useChat } from '@ai-sdk/react';
import { DefaultChatTransport } from 'ai';
import { useMemo } from 'react';

export default function AgentChat() {
  const {
    messages,
    setMessages,
    sendMessage,
    status,
  } = useChat({
    transport: new DefaultChatTransport({ api: '/api/chat' }),
  });

  function submit(text: string) {
    const optimisticId = `optimistic-${crypto.randomUUID()}`;

    setMessages(prev => [
      ...prev,
      {
        id: optimisticId,
        role: 'assistant',
        parts: [{ type: 'text', text: '' }],
        metadata: {
          optimistic: true,
          phase: 'thinking',
          label: 'Analyzing request…',
        },
      },
    ]);

    sendMessage(
      { text },
      {
        metadata: { optimisticAssistantId: optimisticId },
      },
    );
  }

  return null;
}

type AgentPhase =
  | 'thinking'
  | 'tool-requested'
  | 'tool-running'
  | 'summarizing'
  | 'done'
  | 'error';

type OptimisticAgentState = Record<
  string,
  {
    phase: AgentPhase;
    label: string;
    startedAt: number;
    toolName?: string;
  }
>;
